examples.server_side:
import { Table, useServerTable } from '@juv/codego-react-ui'

const { data, columns, loading, serverPagination, reload } = useServerTable({
  url: '/api/users',
  debounce: 300,
  transform: (res) => res.data,
  onSuccess: (data) => console.log('Loaded', data),
})

<Table
  data={data}
  columns={columns}
  loading={loading}
  serverPagination={serverPagination}
  defaultActions={{
    baseUrl: '/api/users',
    editForm: [
      { key: 'name', label: 'Name', required: true },
      { key: 'email', label: 'Email', validation: 'email' }
    ],
    permissions: (item) => ({ edit: item.role === 'admin', delete: true }),
    beforeDelete: async (item) => confirm('Delete?'),
    deleteConfirm: { title: 'Delete User', message: 'Are you sure?' },
    onSuccess: () => reload(),
  }}
/>

examples.controlled_state:
import { Table } from '@juv/codego-react-ui'
import { useState } from 'react'

const [searchValue, setSearchValue] = useState('')
const [page, setPage] = useState(1)
const [sort, setSort] = useState([])
const [columnVisibility, setColumnVisibility] = useState({})

<Table
  data={data}
  columns={columns}
  searchValue={searchValue}
  onSearchChange={setSearchValue}
  page={page}
  onPageChange={setPage}
  sort={sort}
  onSortChange={setSort}
  columnVisibility={columnVisibility}
  onColumnVisibilityChange={setColumnVisibility}
  expandable
  renderExpanded={(item) => <UserDetails user={item} />}
  exportable
  onExport={(type) => exportData(type)}
  keyboardNavigation
  theme="dark"
  meta={{ userId: 123 }}
  actions={{
    archive: (item) => archiveUser(item),
    duplicate: (item) => duplicateUser(item),
  }}
/>

examples.ai_agent:
import { Table } from '@juv/codego-react-ui'
import { useReducer } from 'react'

const tableReducer = (state, action) => {
  switch (action.type) {
    case 'SEARCH': return { ...state, search: action.payload, page: 1 }
    case 'SORT': return { ...state, sort: action.payload }
    case 'PAGE': return { ...state, page: action.payload }
    case 'VISIBILITY': return { ...state, columnVisibility: action.payload }
    case 'ROW_SELECT': return { ...state, selectedRow: action.payload }
    default: return state
  }
}

const [state, dispatch] = useReducer(tableReducer, initialState)

<Table
  data={state.data}
  columns={state.columns}
  loading={state.loading}
  error={state.error}
  searchValue={state.search}
  onSearchChange={(v) => dispatch({ type: 'SEARCH', payload: v })}
  sort={state.sort}
  onSortChange={(s) => dispatch({ type: 'SORT', payload: s })}
  page={state.page}
  onPageChange={(p) => dispatch({ type: 'PAGE', payload: p })}
  columnVisibility={state.columnVisibility}
  onColumnVisibilityChange={(v) => dispatch({ type: 'VISIBILITY', payload: v })}
  onRowClick={(item) => dispatch({ type: 'ROW_SELECT', payload: item })}
  meta={state.meta}
  actions={state.actions}
/>
